// -----------------------------------------------------
// C3: Physical sensing components
// -----------------------------------------------------
instance SwingAngleEncoder : DTDFVocab:SensingComponent [
    base:desc "Swing‑angle encoder measuring hoist swing angle"
    DTDFVocab:producedData SwingAngleMeasurement
]

instance Anemometer : DTDFVocab:SensingComponent [
    base:desc "Anemometer measuring ambient wind speed"
    DTDFVocab:producedData WindSpeedMeasurement
]

instance MotorStatusSensor : DTDFVocab:SensingComponent [
    base:desc "Sensor reading motor status feedback from TMC4671‑Eval controllers"
    DTDFVocab:producedData MotorStatusMeasurement
]

// -----------------------------------------------------
// C4: Physical-to-virtual interaction (DataTransmitted)
// -----------------------------------------------------
instance SwingAngleMeasurement : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom SwingAngleEncoder
]

instance WindSpeedMeasurement : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom Anemometer
]

instance MotorStatusMeasurement : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorStatusSensor
]

// -----------------------------------------------------
// C10: Data (time‑series, trajectories, simulation traces)
// -----------------------------------------------------
instance SwingAngleTimeSeries : DTDFVocab:Data [
    base:desc "Time‑series swing angle measurements stored in TimescaleDB"
    DTDFVocab:fromData SwingAngleMeasurement
    DTDFVocab:inputTo MqttBrokerEnabler, TimescaleDbEnabler
]

instance WindSpeedTimeSeries : DTDFVocab:Data [
    base:desc "Time‑series wind speed measurements stored in TimescaleDB"
    DTDFVocab:fromData WindSpeedMeasurement
    DTDFVocab:inputTo MqttBrokerEnabler, TimescaleDbEnabler
]

instance MotorStatusTimeSeries : DTDFVocab:Data [
    base:desc "Time‑series motor status feedback stored in TimescaleDB"
    DTDFVocab:fromData MotorStatusMeasurement
    DTDFVocab:inputTo MqttBrokerEnabler, TimescaleDbEnabler
]

instance GeneratedTrajectoryData : DTDFVocab:Data [
    base:desc "Optimal swing‑free trajectory plans generated by the trajectory service"
    DTDFVocab:inputTo MqttBrokerEnabler, TimescaleDbEnabler, ValidationEnabler
]

instance SimulatedStateTraceData : DTDFVocab:Data [
    base:desc "State traces from crane dynamics simulation used for validation"
    DTDFVocab:inputTo TimescaleDbEnabler, ValidationEnabler
]

// -----------------------------------------------------
// C2: Acting components
// -----------------------------------------------------
instance CartStepperMotor : DTDFVocab:ActingComponent [
    base:desc "Cart stepper motor driven by a TMC4671‑Eval controller"
]

instance HoistStepperMotor : DTDFVocab:ActingComponent [
    base:desc "Hoist stepper motor driven by a TMC4671‑Eval controller"
]

instance ElectromagnetActuator : DTDFVocab:ActingComponent [
    base:desc "Electromagnet at the hoist end for picking up and releasing pucks"
]

// -----------------------------------------------------
// C11: Models
// -----------------------------------------------------
instance KinematicModel : DTDFVocab:Model [
    base:desc "Kinematic model used for optimal trajectory planning and crane dynamics simulation"
    DTDFVocab:inputTo TrajectoryGeneratorEnabler, SimulationEnabler
]

instance CadGeometryModel : DTDFVocab:Model [
    base:desc "CAD geometry of the gantry crane for 3‑D visualization"
    DTDFVocab:inputTo VisualizationEnabler
]

// -----------------------------------------------------
// C8: Enablers (software containers, libraries, brokers)
// -----------------------------------------------------
instance MqttBrokerEnabler : DTDFVocab:Enabler [
    base:desc "Eclipse Mosquitto MQTT broker container publishing sensor and command data"
    DTDFVocab:enables RealTimeDataLoggingService,
                     CraneSimulationService,
                     TrajectoryGenerationService,
                     HumanMachineInterfaceService
]

instance TimescaleDbEnabler : DTDFVocab:Enabler [
    base:desc "TimescaleDB container persisting historic measurements, trajectories and simulation traces"
    DTDFVocab:enables RealTimeDataLoggingService,
                     ContinuousValidationService,
                     HumanMachineInterfaceService
]

instance VisualizationEnabler : DTDFVocab:Enabler [
    base:desc "Grafana container rendering dashboards with CAD geometry and sensor trends"
    DTDFVocab:enables GrafanaVisualizationService
]

instance TrajectoryGeneratorEnabler : DTDFVocab:Enabler [
    base:desc "Python gantrylib library that computes swing‑free optimal trajectories"
    DTDFVocab:enables TrajectoryGenerationService
]

instance SimulationEnabler : DTDFVocab:Enabler [
    base:desc "Python simulation service replicating crane dynamics based on the kinematic model"
    DTDFVocab:enables CraneSimulationService
]

instance ValidationEnabler : DTDFVocab:Enabler [
    base:desc "Continuous validation service comparing executed trajectories with simulated ones"
    DTDFVocab:enables ContinuousValidationService
]

instance HMIEnabler : DTDFVocab:Enabler [
    base:desc "Human‑Machine Interface container for operator control and configuration"
    DTDFVocab:enables HumanMachineInterfaceService
]

// -----------------------------------------------------
// C6: Services (digital twin capabilities)
// -----------------------------------------------------
instance RealTimeDataLoggingService : DTDFVocab:Service [
    base:desc "Logs incoming sensor data in real time to TimescaleDB"
    DTDFVocab:provides SystemHealthDashboardInsight
]

instance GrafanaVisualizationService : DTDFVocab:Service [
    base:desc "Provides Grafana‑based visualization dashboards for system health monitoring"
    DTDFVocab:provides SystemHealthDashboardInsight
]

instance TrajectoryGenerationService : DTDFVocab:Service [
    base:desc "Generates optimal swing‑free trajectories using the kinematic model"
    DTDFVocab:provides GenerateOptimizedTrajectoryAction
]

instance CraneSimulationService : DTDFVocab:Service [
    base:desc "Simulates crane dynamics to predict state evolution for a given trajectory"
    DTDFVocab:provides SimulatedStateTraceInsight
]

instance ContinuousValidationService : DTDFVocab:Service [
    base:desc "Continuously validates executed trajectories against simulated traces and raises alerts"
    DTDFVocab:provides ModelDeviationAlertInsight
]

instance HumanMachineInterfaceService : DTDFVocab:Service [
    base:desc "Human‑Machine Interface for operator control, configuration and corrective actions"
    DTDFVocab:provides OperatorCorrectiveAction
]

// -----------------------------------------------------
// C17: Insights and Actions
// -----------------------------------------------------
instance SystemHealthDashboardInsight : DTDFVocab:Insight [
    base:desc "Grafana dashboards visualizing current system health, sensor trends and alarms"
]

instance ModelDeviationAlertInsight : DTDFVocab:Insight [
    base:desc "Alert indicating significant deviation between executed and simulated trajectories"
]

instance SimulatedStateTraceInsight : DTDFVocab:Insight [
    base:desc "Insight into simulated crane dynamics useful for performance analysis"
]

instance GenerateOptimizedTrajectoryAction : DTDFVocab:Action [
    base:desc "Computes and issues a swing‑free optimal trajectory to the crane"
    DTDFVocab:IsAutomatic true
]

instance OperatorCorrectiveAction : DTDFVocab:Action [
    base:desc "Operator can manually adjust trajectory or system parameters via the HMI"
    DTDFVocab:IsAutomatic false
]

instance virtual_to_physical_interaction : DTDFVocab:VirtualToPhysical [
    base:desc "DT services (e.g., the Control Application and Trajectory Generator Service) send motion set‑points, velocity commands, and electromagnet activation signals through the Python interface to the motor controllers and Arduino, thereby commanding the crane’s movement."
